class AuthenticationManager(private val sharedPreferences: SharedPreferences) {
    private val AUTH_TOKEN_KEY = "auth_token"
    private val USER_ID_KEY = "user_id"

    fun saveAuthToken(authToken: String) {
        sharedPreferences.edit().putString(AUTH_TOKEN_KEY, authToken).apply()
    }

    fun getSavedAuthToken(): String? {
        return sharedPreferences.getString(AUTH_TOKEN_KEY, null)
    }

    fun saveUserId(userId: Long) {
        sharedPreferences.edit().putLong(USER_ID_KEY, userId).apply()
    }

    fun getSavedUserId(): Long? {
        return sharedPreferences.getLong(USER_ID_KEY, null)
    }
}